import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"2014年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2014年/核心总结.md","filePath":"01_letters/2014年/核心总结.md"}'),t={name:"01_letters/2014年/核心总结.md"};function o(h,l,n,u,d,s){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_2014年巴菲特致股东信核心总结" tabindex="-1">2014年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2014年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2014年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长8.3%，股价上涨27.0%</li><li>标普500上涨13.7%</li><li>50年复合年增长率：账面价值19.4%，股价21.6%</li><li>50年累计涨幅：股价1,826,163%</li></ul><h2 id="伯克希尔50周年回顾" tabindex="-1">伯克希尔50周年回顾 <a class="header-anchor" href="#伯克希尔50周年回顾" aria-label="Permalink to &quot;伯克希尔50周年回顾&quot;">​</a></h2><h3 id="关键历史节点" tabindex="-1">关键历史节点 <a class="header-anchor" href="#关键历史节点" aria-label="Permalink to &quot;关键历史节点&quot;">​</a></h3><p><strong>1964年转折：</strong></p><ul><li>西伯里·斯坦顿提出以11.375美元回购股票</li><li>巴菲特因八分之一点差异拒绝出售</li><li>随后积极买入，1965年4月获得控制权</li></ul><p><strong>1967年NICO收购：</strong></p><ul><li>以860万美元收购国民赔偿公司</li><li>巴菲特犯下巨大错误：应为个人合伙购买而非伯克希尔</li><li>约1,000亿美元从合伙人转移给陌生人</li></ul><p><strong>1972年See&#39;s Candy收购：</strong></p><ul><li>查理·芒格的蓝图：以公平价格购买美好企业</li><li>以2,500万美元购买，税前利润400万美元</li><li>迄今产生19亿美元税前利润</li></ul><h3 id="企业集团优势" tabindex="-1">企业集团优势 <a class="header-anchor" href="#企业集团优势" aria-label="Permalink to &quot;企业集团优势&quot;">​</a></h3><p><strong>为何企业集团形式对伯克希尔有利：</strong></p><ol><li><p><strong>资本配置灵活性</strong></p><ul><li>可在不同业务间免税转移资金</li><li>不受单一行业限制</li><li>可购买企业片段（股票）</li></ul></li><li><p><strong>出售者首选</strong></p><ul><li>永久家园，人员和文化被保留</li><li>财务实力增强</li><li>无需与银行和分析师打交道</li></ul></li><li><p><strong>避免分拆的理由</strong></p><ul><li>丧失控制价值</li><li>资本配置灵活性受损</li><li>某些税收优势消失</li></ul></li></ol><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="van-tuyl汽车集团" tabindex="-1">Van Tuyl汽车集团 <a class="header-anchor" href="#van-tuyl汽车集团" aria-label="Permalink to &quot;Van Tuyl汽车集团&quot;">​</a></h3><ul><li>78家汽车经销商</li><li>全国第五大汽车集团</li><li>未来将大幅扩张</li></ul><h3 id="补强收购" tabindex="-1">补强收购 <a class="header-anchor" href="#补强收购" aria-label="Permalink to &quot;补强收购&quot;">​</a></h3><ul><li>31项，总成本78亿美元</li><li>最大：金霸王（2015年完成）</li></ul><h2 id="五大业务表现" tabindex="-1">五大业务表现 <a class="header-anchor" href="#五大业务表现" aria-label="Permalink to &quot;五大业务表现&quot;">​</a></h2><h3 id="动力五巨头" tabindex="-1">&quot;动力五巨头&quot; <a class="header-anchor" href="#动力五巨头" aria-label="Permalink to &quot;&quot;动力五巨头&quot;&quot;">​</a></h3><ul><li>BNSF、IMC（原Iscar）、Lubrizol、Marmon、BHE</li><li>税前利润124亿美元，创纪录</li><li>比2013年增加16亿美元</li></ul><h3 id="bnsf服务问题" tabindex="-1">BNSF服务问题 <a class="header-anchor" href="#bnsf服务问题" aria-label="Permalink to &quot;BNSF服务问题&quot;">​</a></h3><ul><li>2014年让许多客户失望</li><li>2015年将投入60亿美元改善</li><li>比任何铁路公司单年支出高近50%</li></ul><h2 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h2><ul><li>创纪录的150亿美元</li><li>90%投放在美国</li><li>BHE和BNSF合计116亿美元</li></ul><h2 id="投资管理传承" tabindex="-1">投资管理传承 <a class="header-anchor" href="#投资管理传承" aria-label="Permalink to &quot;投资管理传承&quot;">​</a></h2><h3 id="todd-combs和ted-weschler" tabindex="-1">Todd Combs和Ted Weschler <a class="header-anchor" href="#todd-combs和ted-weschler" aria-label="Permalink to &quot;Todd Combs和Ted Weschler&quot;">​</a></h3><ul><li>各自管理超过70亿美元</li><li>超越标普500</li><li>被任命监管至少一家子公司</li><li>在收购评估方面为CEO提供帮助</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="股票回购的正确理解" tabindex="-1">股票回购的正确理解 <a class="header-anchor" href="#股票回购的正确理解" aria-label="Permalink to &quot;股票回购的正确理解&quot;">​</a></h3><ul><li>只在低于内在价值时回购</li><li>回购增加每股内在价值</li><li>回购决策应基于价格/价值，而非抵消稀释</li></ul><h3 id="ibm回购案例分析" tabindex="-1">IBM回购案例分析 <a class="header-anchor" href="#ibm回购案例分析" aria-label="Permalink to &quot;IBM回购案例分析&quot;">​</a></h3><ul><li>若股价200美元：500亿美元回购2.5亿股，持股7%</li><li>若股价300美元：回购1.67亿股，持股6.5%</li><li>低价回购对长期股东更有利</li></ul><h3 id="关于波动性" tabindex="-1">关于波动性 <a class="header-anchor" href="#关于波动性" aria-label="Permalink to &quot;关于波动性&quot;">​</a></h3><ul><li>波动性≠风险</li><li>以货币计价的工具风险更高</li><li>股票长期比现金更安全</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><ul><li>连续12年承保盈利，累计240亿美元</li><li>浮存金增至839亿美元</li><li>承诺支付能力无与伦比</li><li>八份超过10亿美元保费的P/C保单，全部由伯克希尔承保</li></ul><h2 id="查理·芒格的补充评论" tabindex="-1">查理·芒格的补充评论 <a class="header-anchor" href="#查理·芒格的补充评论" aria-label="Permalink to &quot;查理·芒格的补充评论&quot;">​</a></h2><h3 id="伯克希尔系统要素" tabindex="-1">伯克希尔系统要素 <a class="header-anchor" href="#伯克希尔系统要素" aria-label="Permalink to &quot;伯克希尔系统要素&quot;">​</a></h3><ol><li>分散的企业集团结构</li><li>子公司CEO极度自主</li><li>总部几乎什么都没有</li><li>保险业务产生大量浮存金</li><li>无重大全系统人事制度</li><li>董事长保留少数关键活动</li><li>新子公司以现金购买</li><li>只要留存收益创造价值就不支付股息</li><li>几乎不出售子公司</li></ol><h3 id="成功四因素" tabindex="-1">成功四因素 <a class="header-anchor" href="#成功四因素" aria-label="Permalink to &quot;成功四因素&quot;">​</a></h3><ol><li>巴菲特的建设性特质</li><li>伯克希尔系统的建设性特质</li><li>好运气</li><li>股东和仰慕者的奉献</li></ol><h2 id="未来50年展望" tabindex="-1">未来50年展望 <a class="header-anchor" href="#未来50年展望" aria-label="Permalink to &quot;未来50年展望&quot;">​</a></h2><h3 id="关键预测" tabindex="-1">关键预测 <a class="header-anchor" href="#关键预测" aria-label="Permalink to &quot;关键预测&quot;">​</a></h3><ol><li>耐心股东永久资本损失风险极低</li><li>伯克希尔遭遇财务困难的可能性接近零</li><li>每年都能增加潜在每股盈利能力</li><li>长期收益率将低于过去50年</li><li>超越美国平均公司，但优势不大</li></ol><h3 id="继任安排" tabindex="-1">继任安排 <a class="header-anchor" href="#继任安排" aria-label="Permalink to &quot;继任安排&quot;">​</a></h3><ul><li>CEO应来自董事会熟悉的内部候选人</li><li>相对年轻，长期任职</li><li>需理性、冷静、果断，理解商业和人类行为</li><li>知道自己的局限</li><li>全情投入公司，非自负和贪婪驱动</li></ul><h3 id="文化延续" tabindex="-1">文化延续 <a class="header-anchor" href="#文化延续" aria-label="Permalink to &quot;文化延续&quot;">​</a></h3><ul><li>霍华德·巴菲特作为非执行董事长</li><li>确保更换错误CEO更容易</li><li>对抗企业衰败ABC：傲慢、官僚、自满</li></ul><h2 id="企业文化核心" tabindex="-1">企业文化核心 <a class="header-anchor" href="#企业文化核心" aria-label="Permalink to &quot;企业文化核心&quot;">​</a></h2><ul><li>董事费用象征性，无期权或限制性股票</li><li>不购买董事和高管责任保险</li><li>董事穿着股东鞋子走</li><li>&quot;虽然我们的形式是公司，我们的态度是合伙关系&quot;</li></ul>',52)])])}const q=a(t,[["render",o]]);export{b as __pageData,q as default};
